  1104→// Fallback chain: Cache → OpenAI TTS → null (browser Web Speech API fallback)
  1105→async function textToSpeech(text, options = {}) {
  1106→  const pool = require('./db');
  1107→  const crypto = require('crypto');
  1108→
  1109→  try {
  1110→    const voice = options.voice || 'nova';
  1111→    const speed = options.speed || 1.0;
