  1114→    const truncatedText = text.length > 4000 ? text.substring(0, 4000) : text;
  1115→
  1116→    // Generate cache key from text + voice
  1117→    const cacheKey = crypto.createHash('sha256').update(`${voice}:${truncatedText}`).digest('hex');
  1118→
  1119→    // Check cache first — serves audio even when daily token limit is exhausted
  1120→    try {
  1121→      const cached = await pool.query(
  1122→        'SELECT audio_data FROM tts_cache WHERE text_hash = $1',
  1123→        [cacheKey]
  1124→      );
  1125→      if (cached.rows.length > 0 && cached.rows[0].audio_data) {
  1126→        const buf = Buffer.from(cached.rows[0].audio_data);
  1127→        console.log(`[tts] Cache HIT: ${truncatedText.length} chars, ${buf.length} bytes (voice: ${voice})`);
  1128→        return buf;
  1129→      }
  1130→    } catch (cacheErr) {
  1131→      // Cache miss or table doesn't exist yet — continue to API
  1132→      console.log(`[tts] Cache check failed (${cacheErr.message}), proceeding to API`);
  1133→    }
  1134→
  1135→    console.log(`[tts] Cache MISS — generating speech: ${truncatedText.length} chars, voice: ${voice}`);
  1136→
  1137→    // Use provider service with automatic fallback
  1138→    const buf = await aiProvider.textToSpeech(truncatedText, {
  1139→      voice,
  1140→      speed,
  1141→      subscriptionId: options.subscriptionId,
  1142→    });
  1143→
  1144→    if (!buf) {
  1145→      console.log('[tts] All providers failed, returning null for browser fallback');
  1146→      return null;
  1147→    }
  1148→
  1149→    console.log(`[tts] Generated ${buf.length} bytes of MP3 audio`);
  1150→
  1151→    // Cache the audio for future use (non-blocking)
  1152→    if (buf.length > 100) {
  1153→      pool.query(
  1154→        `INSERT INTO tts_cache (text_hash, voice, audio_data, text_preview)
  1155→         VALUES ($1, $2, $3, $4)
  1156→         ON CONFLICT (text_hash) DO NOTHING`,
  1157→        [cacheKey, voice, buf, truncatedText.substring(0, 100)]
  1158→      ).then(() => {
  1159→        console.log(`[tts] Cached audio for: "${truncatedText.substring(0, 50)}..."`);
  1160→      }).catch(err => {
  1161→        // Non-fatal — caching failure doesn't break TTS
  1162→        console.warn(`[tts] Cache write failed: ${err.message}`);
  1163→      });
  1164→    }
  1165→
  1166→    return buf;
  1167→  } catch (err) {
  1168→    console.error('[tts] Error:', err.message || err);
  1169→    return null;
  1170→  }
  1171→}
