     5→
     6→// ─── Rate Limiting (in-memory) ──────────────────────────────────────────────
     7→const loginAttempts = new Map(); // ip -> { count, firstAttempt }
     8→const RATE_LIMIT_WINDOW = 15 * 60 * 1000; // 15 minutes
     9→const MAX_ATTEMPTS = 5;
    10→
    11→function checkRateLimit(ip) {
    12→  const now = Date.now();
    13→  const record = loginAttempts.get(ip);
    14→
    15→  if (!record || (now - record.firstAttempt) > RATE_LIMIT_WINDOW) {
    16→    loginAttempts.set(ip, { count: 1, firstAttempt: now });
    17→    return { allowed: true, remaining: MAX_ATTEMPTS - 1 };
    18→  }
    19→
    20→  if (record.count >= MAX_ATTEMPTS) {
    21→    const retryAfter = Math.ceil((RATE_LIMIT_WINDOW - (now - record.firstAttempt)) / 1000);
    22→    return { allowed: false, retryAfter };
    23→  }
    24→
    25→  record.count++;
    26→  return { allowed: true, remaining: MAX_ATTEMPTS - record.count };
    27→}
    28→
    29→// Clean up old rate limit entries every 30 minutes
    30→setInterval(() => {
    31→  const now = Date.now();
    32→  for (const [ip, record] of loginAttempts.entries()) {
    33→    if ((now - record.firstAttempt) > RATE_LIMIT_WINDOW) {
    34→      loginAttempts.delete(ip);
    35→    }
    36→  }
    37→}, 30 * 60 * 1000);
    38→
    39→// ─── Admin Credentials ─────────────────────────────────────────────────────
    40→// Generate a default password if not set in env
    41→let ADMIN_PASSWORD_HASH = null;
    42→const ADMIN_USERNAME = process.env.ADMIN_USERNAME || 'admin';
    43→
    44→async function initAdminCredentials() {
    45→  const password = process.env.ADMIN_PASSWORD;
    46→
    47→  if (password) {
    48→    ADMIN_PASSWORD_HASH = await bcrypt.hash(password, 12);
    49→    console.log('[admin] Admin credentials loaded from env vars');
    50→  } else {
    51→    // Generate a strong default password
    52→    const defaultPassword = crypto.randomBytes(16).toString('base64url');
    53→    ADMIN_PASSWORD_HASH = await bcrypt.hash(defaultPassword, 12);
    54→    console.log('');
    55→    console.log('╔══════════════════════════════════════════════════════════════╗');
    56→    console.log('║                    ADMIN CREDENTIALS                         ║');
    57→    console.log('╠══════════════════════════════════════════════════════════════╣');
    58→    console.log(`║  Username: ${ADMIN_USERNAME.padEnd(48)}║`);
    59→    console.log(`║  Password: ${defaultPassword.padEnd(48)}║`);
    60→    console.log('║                                                              ║');
    61→    console.log('║  Set ADMIN_PASSWORD env var to use your own password.        ║');
    62→    console.log('╚══════════════════════════════════════════════════════════════╝');
    63→    console.log('');
    64→  }
    65→}
    66→
    67→// Initialize on module load
    68→initAdminCredentials();
