    70→// ─── Middleware ──────────────────────────────────────────────────────────────
    71→function requireAdmin(req, res, next) {
    72→  if (req.session && req.session.isAdmin) {
    73→    return next();
    74→  }
    75→  return res.status(401).json({ error: 'Admin authentication required' });
    76→}
    77→
    78→// ─── Routes ─────────────────────────────────────────────────────────────────
    79→
    80→// POST /api/admin/login
    81→router.post('/login', async (req, res) => {
    82→  const ip = req.ip || req.connection.remoteAddress || 'unknown';
    83→  const rateCheck = checkRateLimit(ip);
    84→
    85→  if (!rateCheck.allowed) {
    86→    return res.status(429).json({
    87→      error: 'Too many login attempts',
    88→      retryAfter: rateCheck.retryAfter,
    89→      message: `Too many failed login attempts. Try again in ${Math.ceil(rateCheck.retryAfter / 60)} minutes.`,
    90→    });
    91→  }
    92→
    93→  const { username, password } = req.body;
    94→
    95→  if (!username || !password) {
    96→    return res.status(400).json({ error: 'Username and password required' });
    97→  }
    98→
    99→  // Wait for hash to be ready
   100→  if (!ADMIN_PASSWORD_HASH) {
   101→    return res.status(503).json({ error: 'Server initializing, try again in a moment' });
   102→  }
   103→
   104→  const usernameMatch = username === ADMIN_USERNAME;
   105→  const passwordMatch = await bcrypt.compare(password, ADMIN_PASSWORD_HASH);
   106→
   107→  if (!usernameMatch || !passwordMatch) {
   108→    return res.status(401).json({ error: 'Invalid credentials' });
   109→  }
   110→
   111→  // Set admin session
   112→  req.session.isAdmin = true;
   113→  req.session.adminLoginAt = new Date().toISOString();
   114→
   115→  // Reset rate limiter on success
   116→  loginAttempts.delete(ip);
   117→
   118→  return res.json({
   119→    success: true,
   120→    message: 'Admin login successful',
   121→    user: { username: ADMIN_USERNAME, role: 'admin' },
   122→  });
   123→});
   124→
   125→// GET /api/admin/me
   126→router.get('/me', (req, res) => {
   127→  if (req.session && req.session.isAdmin) {
   128→    return res.json({
   129→      authenticated: true,
   130→      user: {
   131→        username: ADMIN_USERNAME,
   132→        role: 'admin',
   133→        loginAt: req.session.adminLoginAt,
   134→      },
   135→    });
   136→  }
   137→  return res.status(401).json({ authenticated: false });
   138→});
   139→
   140→// POST /api/admin/logout
   141→router.post('/logout', (req, res) => {
   142→  if (req.session) {
   143→    req.session.isAdmin = false;
   144→    req.session.adminLoginAt = null;
   145→  }
   146→  return res.json({ success: true, message: 'Logged out' });
   147→});
   148→
   149→module.exports = router;
   150→module.exports.requireAdmin = requireAdmin;
